mapper.select:
SELECT v.id, v.memory_id AS memoryId, v.version_no AS versionNo, v.version_status AS versionStatus, v.source_task_id AS sourceTaskId, v.success_assertion AS successAssertion, v.summary, v.create_reason AS createReason, v.create_user_id AS createUserId, v.create_time AS createTime, v.update_time AS updateTime FROM agent_memory_version v
AND v.memory_id = #{pageRequest.memoryId}
AND v.version_no = #{pageRequest.versionNo}
AND v.version_status = #{pageRequest.versionStatus}
AND v.source_task_id = #{pageRequest.sourceTaskId}
ORDER BY v.create_time DESC
